import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringReader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    private static final CSVFormat MOCK_FORMAT = mock(CSVFormat.class);

    @BeforeEach
    void setUp() {
        // Reset mocks before each test if needed
        Mockito.reset(MOCK_FORMAT);
    }

    @Test
    void parse_NullString_ThrowsNullPointerException() {
        try (MockedStatic<Assertions> assertions = Mockito.mockStatic(Assertions.class)) {
            assertions.when(() -> Assertions.notNull(null, "string")).thenThrow(new NullPointerException("string"));
            NullPointerException exception = assertThrows(NullPointerException.class, () -> CSVParser.parse((String) null, MOCK_FORMAT));
            assertEquals("string", exception.getMessage());
        }
    }

    @Test
    void parse_NullFormat_ThrowsNullPointerException() {
        try (MockedStatic<Assertions> assertions = Mockito.mockStatic(Assertions.class)) {
            assertions.when(() -> Assertions.notNull("data", "format")).thenThrow(new NullPointerException("format"));
            NullPointerException exception = assertThrows(NullPointerException.class, () -> CSVParser.parse("data", null));
            assertEquals("format", exception.getMessage());
        }
    }

    @Test
    void parse_ValidStringAndFormat_ReturnsCSVParser() throws IOException {
        String input = "header1,header2\nvalue1,value2";
        CSVParser parser = CSVParser.parse(input, MOCK_FORMAT);
        assertNotNull(parser);
        // Because constructor uses StringReader, the internal reader should not be null
        assertFalse(parser.isClosed());
        assertEquals(MOCK_FORMAT, parser.format);
        // The record list should be empty initially
        assertNotNull(parser.record);
        assertEquals(0, parser.record.size());
    }

}
